import{_ as e,c as p,o as n,ae as t}from"./chunks/framework.Dh1jimFm.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"client-doc/core/certification.md","filePath":"client-doc/core/certification.md","lastUpdated":1770358354000}'),s={name:"client-doc/core/certification.md"};function i(o,a,l,r,c,h){return n(),p("div",null,a[0]||(a[0]=[t(`<h3 id="jwt认证实现" tabindex="-1">JWT认证实现 <a class="header-anchor" href="#jwt认证实现" aria-label="Permalink to &quot;JWT认证实现&quot;">​</a></h3><p>ENFI脚手架内置了完整的JWT认证体系，开箱即用：</p><h4 id="认证流程概述" tabindex="-1">认证流程概述 <a class="header-anchor" href="#认证流程概述" aria-label="Permalink to &quot;认证流程概述&quot;">​</a></h4><p>ENFI框架基于JWT（JSON Web Token）实现了完整的认证机制，通过标准的Token验证方式确保系统访问安全。认证流程采用多层验证策略，涵盖用户凭证校验、验证码验证、密码时效检查及环境差异化处理。</p><h4 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h4><ol><li>多层次安全验证 基础凭证验证：用户名与密码的完整性检查</li></ol><p>用户存在性验证：验证用户账户在系统中的注册状态</p><p>动态验证码机制：支持短信/邮箱验证码二次验证</p><p>密码时效控制：强制密码定期更新策略（默认180天）</p><ol start="2"><li>环境自适应认证 开发环境（dev）：直接使用数据库账户验证，便于开发调试</li></ol><p>生产环境（prod）：集成统一认证服务（如LDAP/AD域认证），确保企业级安全标准</p><ol start="3"><li>Token管理机制 JWT令牌生成：验证成功后生成加密的访问令牌</li></ol><p>Token有效期控制：可配置的令牌过期时间</p><p>统一响应格式：标准化登录响应数据结构</p><p>JWT配置 yaml</p><h4 id="jwt令牌配置" tabindex="-1">JWT令牌配置 <a class="header-anchor" href="#jwt令牌配置" aria-label="Permalink to &quot;JWT令牌配置&quot;">​</a></h4><p>token:</p><h4 id="令牌在http请求头中的自定义标识" tabindex="-1">令牌在HTTP请求头中的自定义标识 <a class="header-anchor" href="#令牌在http请求头中的自定义标识" aria-label="Permalink to &quot;令牌在HTTP请求头中的自定义标识&quot;">​</a></h4><p>header: Authorization</p><h4 id="令牌签名密钥-长度至少32位-建议各项目独立生成高强度随机字符串" tabindex="-1">令牌签名密钥 - 长度至少32位，建议各项目独立生成高强度随机字符串 <a class="header-anchor" href="#令牌签名密钥-长度至少32位-建议各项目独立生成高强度随机字符串" aria-label="Permalink to &quot;令牌签名密钥 - 长度至少32位，建议各项目独立生成高强度随机字符串&quot;">​</a></h4><p>secret: abcdefghijklmnopqrstuvwxyz</p><h4 id="令牌有效期-单位-分钟-默认30分钟" tabindex="-1">令牌有效期（单位：分钟，默认30分钟） <a class="header-anchor" href="#令牌有效期-单位-分钟-默认30分钟" aria-label="Permalink to &quot;令牌有效期（单位：分钟，默认30分钟）&quot;">​</a></h4><p>expireTime: 30</p><h4 id="框架集成优势" tabindex="-1">框架集成优势 <a class="header-anchor" href="#框架集成优势" aria-label="Permalink to &quot;框架集成优势&quot;">​</a></h4><p>安全防护</p><p>防止暴力破解：验证码机制和登录失败限制</p><p>敏感信息保护：密码加密存储和传输</p><p>会话安全：短期有效的JWT令牌</p><p>可扩展性</p><p>支持多认证源：可配置数据库、LDAP、OAuth等多种认证方式</p><p>验证码可插拔：支持短信、邮箱、图形等多种验证码类型</p><p>密码策略自定义：可调整密码复杂度要求和更新周期</p><p>运维友好</p><p>详细日志记录：完整的认证操作审计日志</p><p>异常处理：统一的错误响应和用户友好提示</p><p>监控支持：登录成功/失败统计和异常报警</p><p>ENFI框架的JWT认证模块为企业级应用提供了标准化、安全可靠且易于维护的认证解决方案，显著减少了认证相关的开发工作量，同时确保了系统安全性。</p><p>application.yaml</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># token配置</span></span>
<span class="line"><span>token:</span></span>
<span class="line"><span>  # 令牌自定义标识</span></span>
<span class="line"><span>  header: Authorization</span></span>
<span class="line"><span>  # 令牌密钥  长度至少32位，建议各项目独立生成高强度随机字符串</span></span>
<span class="line"><span>  secret: abcdefghijklmnopqrstuvwxyz</span></span>
<span class="line"><span>  # 令牌有效期（默认30分钟）</span></span>
<span class="line"><span>  expireTime: 30</span></span></code></pre></div>`,39)]))}const T=e(s,[["render",i]]);export{u as __pageData,T as default};
